"use client";

import { useEffect, useRef } from "react";
import gsap from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";
import { particleStore } from "@/lib/particleStore";

gsap.registerPlugin(ScrollTrigger);

/**
 * Scroll layout: #scroll-root = 400vh, window max scroll = 300vh
 *
 *   Scroll   Progress   Section
 *   ───────  ─────────  ───────────────────────────────────
 *     0 vh     0.000    Hero (section-1 at top: 0)
 *   100 vh     0.333    [disintegration zone — no snap point]
 *   200 vh     0.667    Mục đích (section-2 at top: 200vh)
 *   300 vh     1.000    Core values (section-3 at top: 300vh)
 *
 * Snap anchor points: 0, 0.667, 1.0
 * → scrolling quickly past the midpoint snaps to the next section.
 *
 * Particle phase map (progress 0 → 1):
 *   0.00 – 0.12   introProgress     (particles appear at text)
 *   0.08 – 0.48   scrollProgress    (disintegration)
 *   0.60 – 0.78   assemblyProgress  (sphere forms)
 *   0.80 – 1.00   splitProgress     (sphere → 4 mini-circles)
 */
export default function ScrollController() {
  const heroTitleRef = useRef<HTMLElement | null>(null);

  useEffect(() => {
    heroTitleRef.current =
      document.querySelector<HTMLElement>("[data-hero-title]");

    const ctx = gsap.context(() => {
      ScrollTrigger.create({
        trigger: "#scroll-root",
        start: "top top",
        end: "bottom bottom",
        scrub: 1.0,

        // ── Snap to section anchor points ─────────────────────────────────
        // Snap at: Hero(0), Mục đích(200/300=0.667), Core values(300/300=1.0)
        snap: {
          snapTo: [0, 0.667, 1.0],
          duration: { min: 0.35, max: 0.75 },
          delay: 0.08,
          ease: "power2.inOut",
          inertia: false,
        },

        onUpdate: (self) => {
          const p = self.progress;

          // ── Hero title fade ──────────────────────────────────────────────
          if (heroTitleRef.current) {
            heroTitleRef.current.style.opacity =
              String(Math.max(0, 1 - p / 0.09));
          }

          // ── Intro ────────────────────────────────────────────────────────
          particleStore.introProgress =
            Math.min(1, Math.max(0, p / 0.12));

          // ── Phases ───────────────────────────────────────────────────────
          const DIS_S = 0.08, DIS_E = 0.48;
          const ASM_S = 0.60, ASM_E = 0.78;
          const SPL_S = 0.80, SPL_E = 1.00;

          if (p < DIS_S) {
            particleStore.scrollProgress   = 0;
            particleStore.assemblyProgress = 0;
            particleStore.splitProgress    = 0;
          } else if (p <= DIS_E) {
            particleStore.scrollProgress   = (p - DIS_S) / (DIS_E - DIS_S);
            particleStore.assemblyProgress = 0;
            particleStore.splitProgress    = 0;
          } else if (p < ASM_S) {
            particleStore.scrollProgress   = 1;
            particleStore.assemblyProgress = 0;
            particleStore.splitProgress    = 0;
          } else if (p <= ASM_E) {
            particleStore.scrollProgress   = 1;
            particleStore.assemblyProgress = (p - ASM_S) / (ASM_E - ASM_S);
            particleStore.splitProgress    = 0;
          } else if (p < SPL_S) {
            particleStore.scrollProgress   = 1;
            particleStore.assemblyProgress = 1;
            particleStore.splitProgress    = 0;
          } else {
            particleStore.scrollProgress   = 1;
            particleStore.assemblyProgress = 1;
            particleStore.splitProgress    = (p - SPL_S) / (SPL_E - SPL_S);
          }
        },
      });
    });

    return () => ctx.revert();
  }, []);

  return null;
}
